package middlewares

import (
	"bytes"
	"errors"
	"io"
	"net/http"
	"strings"

	"crapi.proj/goservice/api/responses"
)

// NoOperatorBody rejects request bodies that contain MongoDB operator keys (any key starting with '$').
func NoOperatorBody(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		body, err := io.ReadAll(r.Body)
		if err != nil {
			responses.ERROR(w, http.StatusBadRequest, err)
			return
		}
		r.Body = io.NopCloser(bytes.NewBuffer(body))
		if strings.Contains(string(body), "\"$") {
			responses.ERROR(w, http.StatusBadRequest, errors.New("request body contains invalid operator"))
			return
		}
		next(w, r)
	}
}
